<?php
namespace Ronu\LaravelFederatedAuth\Services;
use Illuminate\Contracts\Auth\Authenticatable; use Illuminate\Database\Eloquent\Model; use Ronu\LaravelFederatedAuth\Contracts\UserResolverInterface; use Ronu\LaravelFederatedAuth\DTO\AuthContext; use Ronu\LaravelFederatedAuth\DTO\ExternalIdentity; use Ronu\LaravelFederatedAuth\Exceptions\AmbiguousLocalUserException;
class ConfigurableUserResolver implements UserResolverInterface { public function resolveById(string|int $userId, AuthContext $context): ?Authenticatable { $model=config('federated-auth.user.model'); if(!$model||!is_subclass_of($model,Model::class)) return null; return $model::query()->where(config('federated-auth.user.primary_key','id'),$userId)->first(); } public function resolveByExternalIdentity(ExternalIdentity $identity, AuthContext $context): ?Authenticatable { return null; } public function resolveByEmail(ExternalIdentity $identity, AuthContext $context): ?Authenticatable { if(!$identity->email) return null; $model=config('federated-auth.user.model'); if(!$model||!is_subclass_of($model,Model::class)) return null; $q=$model::query()->where(config('federated-auth.user.columns.email','email'),$identity->email); $typeCol=config('federated-auth.user.columns.type'); if($typeCol&&$context->userType) $q->where($typeCol,$context->userType); $users=$q->limit(2)->get(); if($users->count()>1&&config('federated-auth.security.deny_ambiguous_email_match',true)) throw new AmbiguousLocalUserException('More than one local user matches the external provider email.'); return $users->first(); } }
